module RefModule (
	input clk,
	input resetn,
	input request,
	output reg moving);

	parameter IDLE=0, MOVING=1;
	reg state, ctrl_bus_wire;

	always @(posedge clk) begin
		if (~resetn) state <= IDLE;
		else state <= ctrl_bus_wire;
	end

	always_comb begin
		case (state)
			IDLE: ctrl_bus_wire = request ? MOVING : IDLE;
			MOVING: ctrl_bus_wire = IDLE;
			default: ctrl_bus_wire = IDLE;
		endcase
	end

	always @(state) begin
		case (state)
			MOVING: moving = 1;
			default: moving = 0;
		endcase
	end
endmodule
